def checkQwenOutputOnJson():
    with open("test.json","r",encoding="utf-8") as file:
        outputObj = json.load(file)
    return outputObj


def count_chinese_chars(text):
    count = 0
    # 遍历字符串中的每个字符
    for char in text:
        # 判断字符是否为汉字（Unicode编码范围：0x4E00 至 0x9FFF）
        if '\u4e00' <= char <= '\u9fff':
            count += 1
    return count
def trimRow():
    with open("temp4.json","r",encoding="utf-8") as file:
        textStr = file.read()
    resultText = textStr.replace("\n","   ").replace("\r","").replace('"','\\"')
    return resultText

def checkJsonAndText():
    result_json = checkQwenOutputOnJson()
    sentenceList = result_json["sentenceList"]
    text = ""
    for sentence in sentenceList:
        text += sentence["context"]
        print_text = "({emotion})".format(emotion= sentence["emotion"])+sentence['context']
        print(print_text)
    text_count = count_chinese_chars(text)
    with open("test.txt","r",encoding="utf-8") as file:
        new_text = file.read()

    new_text_count = count_chinese_chars(new_text)
    print("json文本数量："+str(text_count))
    print("txt文本数量："+str(new_text_count))

'''
读取test.txt小说内容，去掉多余空行，转换成带序号的数组
'''
def readTestTxtToArray():
    with open("test.txt","r",encoding="utf-8") as file:
        textStr = file.read()
    text_array = textStr.split("\n")
    new_text_array = []
    for text in text_array:
        if text != "":
            new_text_array.append(text)
    return new_text_array
def appendTextMax120(text_array):
    max_text_array = []
    max_text = ""
    for text in text_array:
        if len(max_text) + len(text) < 120:
            max_text += text
        else:
            max_text_array.append(max_text)
            max_text = ""
            continue
    return max_text_array

def check_json_and_text():
    """
    将模型解析的小说章节文本放到test.json里，读取并判断角色是否在角色列表里
    :return:
    """
    with open("test.json","r",encoding="utf-8") as file:
        textStr = json.loads(file.read())
    role_list = []
    for role in textStr["roleList"]:
        role_list.append(role['roleName'])
    for s in textStr["sentenceList"]:
        if s['identity'] == 'role':
            print("哪个角色说的："+s['roleName'])
            if s['roleName'] in role_list:
                print("角色在角色列表里")
            else:
                print("角色不在列表里")
            print("----------------------")
